SELECT
    id, superassist_id, resource_id, resource_type, create_time, privilege_type
FROM suas_superassist_resource_privilege
 1=1

        AND superassist_id = #{assistantId,jdbcType=BIGINT}


        AND resource_id = #{resourceId,jdbcType=BIGINT}


        AND resource_type = #{resourceType,jdbcType=VARCHAR}


ORDER BY create_time DESC

SELECT p.id, p.superassist_id, p.resource_id, p.resource_type, p.create_time, p.privilege_type, r.resource_name, r.resource_desc FROM suas_superassist_resource_privilege p LEFT JOIN ss_resource r ON p.resource_id = r.resource_id WHERE p.superassist_id = #{assistantId,jdbcType=BIGINT}
AND p.privilege_type = #{privilegeType,jdbcType=VARCHAR}
AND p.resource_type = #{resourceType,jdbcType=VARCHAR}
ORDER BY p.create_time DESC

